// src/About.js

import React, { memo } from 'react';
import { motion } from 'framer-motion';

const itemAnim = { initial: { opacity: 0, y: 20 }, whileInView: { opacity: 1, y: 0 }, viewport: { once: true }, transition: { duration: 0.4 } };

const QrGridBackground = memo(() => (
  <div aria-hidden="true" className="pointer-events-none absolute inset-0 overflow-hidden opacity-[0.03] dark:opacity-[0.05]">
    <div className="absolute inset-0 grid grid-cols-8" style={{ gridTemplateRows: 'repeat(4, 1fr)' }}>
      {Array.from({ length: 32 }).map((_, i) => (
        <div key={i} className="border border-purple-500"
          style={{ opacity: 0, animation: `qrCellPulse ${3 + (i % 4)}s ease-in-out ${(i * 0.08) % 3}s infinite` }} />
      ))}
    </div>
  </div>
));
QrGridBackground.displayName = 'QrGridBackground';

const GlowOrbs = memo(() => (
  <div aria-hidden="true" className="pointer-events-none absolute inset-0 overflow-hidden">
    <div className="absolute -top-40 left-1/2 -translate-x-1/2 w-[600px] h-[600px] rounded-full bg-purple-500/8 dark:bg-purple-500/10 blur-[120px]" />
    <div className="absolute bottom-0 right-1/4 w-[400px] h-[400px] rounded-full bg-indigo-500/8 dark:bg-indigo-500/10 blur-[100px]" />
  </div>
));
GlowOrbs.displayName = 'GlowOrbs';

const StatCard = memo(({ emoji, value, label }) => (
  <motion.div
    {...itemAnim}
    className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-6 text-center"
  >
    <div className="text-3xl mb-2">{emoji}</div>
    <p className="text-2xl font-extrabold text-gray-900 dark:text-white">{value}</p>
    <p className="text-xs text-gray-400 dark:text-gray-500 uppercase tracking-wide mt-1">{label}</p>
  </motion.div>
));
StatCard.displayName = 'StatCard';

const ValueCard = memo(({ emoji, title, desc }) => (
  <motion.div
    {...itemAnim}
    className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-6 flex gap-4"
  >
    <span className="text-2xl flex-shrink-0 mt-0.5">{emoji}</span>
    <div>
      <p className="font-bold text-gray-900 dark:text-white mb-1">{title}</p>
      <p className="text-sm text-gray-500 dark:text-gray-400 leading-relaxed">{desc}</p>
    </div>
  </motion.div>
));
ValueCard.displayName = 'ValueCard';

const About = memo(() => (
  <section className="relative min-h-screen bg-gray-50 dark:bg-[#0f0f1a] transition-colors duration-500 overflow-hidden">
    <QrGridBackground />
    <GlowOrbs />

    <div className="relative z-10 max-w-4xl mx-auto px-6 md:px-12 py-24">

      {/* Header */}
      <motion.div {...itemAnim} className="mb-16 text-center">
        <p className="text-sm font-semibold uppercase tracking-widest text-purple-500 dark:text-purple-400 mb-3">
          About
        </p>
        <h1 className="text-5xl md:text-6xl font-extrabold text-gray-900 dark:text-white tracking-tight mb-4">
          Built for Everyone
        </h1>
        <div className="w-16 h-1 bg-gradient-to-r from-purple-500 to-indigo-500 rounded-full mx-auto mb-6" />
        <p className="text-lg text-gray-500 dark:text-gray-400 max-w-2xl mx-auto leading-relaxed">
          Qronetic is a free, privacy-first QR code generator and scanner built to work entirely in your browser — no sign-up, no tracking, no limits.
        </p>
      </motion.div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-16">
        <StatCard emoji="⚡" value="100%" label="Free forever" />
        <StatCard emoji="🔒" value="0"    label="Data collected" />
        <StatCard emoji="🌐" value="10+"  label="QR types" />
        <StatCard emoji="📱" value="All"  label="Devices" />
      </div>

      {/* Story */}
      <motion.div
        {...itemAnim}
        className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-8 mb-8"
      >
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">Our Story</h2>
        <div className="space-y-4 text-gray-500 dark:text-gray-400 leading-relaxed">
          <p>
            Qronetic started with a simple frustration — every QR code tool online either required creating an account, displayed intrusive ads, or charged for basic features that should be free.
          </p>
          <p>
            So we built the tool we always wanted. One that runs entirely in your browser, never touches a server, and gives you full customization without a paywall. Your data stays on your device, period.
          </p>
          <p>
            Today Qronetic supports 10+ QR types, custom styling, batch generation, camera scanning, and more — all completely free, all completely private.
          </p>
        </div>
      </motion.div>

      {/* Values */}
      <motion.div {...itemAnim} className="mb-4">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-6">What We Stand For</h2>
      </motion.div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-16">
        <ValueCard
          emoji="🔒"
          title="Privacy First"
          desc="Everything runs in your browser. No data is sent to any server. No analytics on your content. What you generate stays yours."
        />
        <ValueCard
          emoji="⚡"
          title="Always Free"
          desc="No freemium tricks, no watermarks, no artificial limits. Every feature on Qronetic is and will always be completely free."
        />
        <ValueCard
          emoji="🎨"
          title="Real Customization"
          desc="Colors, dot styles, eye styles, logo overlay, size control — we give you the tools to make QR codes that actually match your brand."
        />
        <ValueCard
          emoji="🌍"
          title="Built for Everyone"
          desc="Whether you're a developer, small business owner, student, or just someone who needs a QR code — Qronetic works for you."
        />
      </div>

      {/* Tech stack */}
      <motion.div
        {...itemAnim}
        className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-8 mb-8"
      >
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">How It Works</h2>
        <p className="text-gray-500 dark:text-gray-400 leading-relaxed mb-4">
          Qronetic is built entirely with web technologies that run locally in your browser. QR generation uses the <span className="text-purple-600 dark:text-purple-400 font-medium">qrcode</span> library, scanning uses <span className="text-purple-600 dark:text-purple-400 font-medium">jsQR</span>, and the entire app is built with <span className="text-purple-600 dark:text-purple-400 font-medium">React</span>.
        </p>
        <p className="text-gray-500 dark:text-gray-400 leading-relaxed">
          No backend, no database, no cloud processing. Your QR codes are generated entirely on your device — which means they're instant, private, and work even offline.
        </p>
      </motion.div>

      {/* CTA */}
      <motion.div {...itemAnim} className="text-center">
        <p className="text-gray-400 dark:text-gray-500 text-sm">
          Built with ❤️ by <span className="text-purple-600 dark:text-purple-400 font-semibold">OH Development</span>
          <span className="mx-2">·</span>
          <a href="mailto:qronetic@gmail.com" className="hover:text-purple-600 dark:hover:text-purple-400 transition-colors duration-200">
            qronetic@gmail.com
          </a>
        </p>
      </motion.div>

    </div>
  </section>
));

About.displayName = 'About';
export default About;